function buildLPS(pattern) {
  const lps = Array(pattern.length).fill(0);
  let len = 0, i = 1;
  while (i < pattern.length) {
    if (pattern[i] === pattern[len]) {
      lps[i++] = ++len;
    } else if (len > 0) {
      len = lps[len - 1];
    } else {
      lps[i++] = 0;
    }
  }
  return lps;
}

function kmpSearch(text, pattern) {
  const lps = buildLPS(pattern);
  let i = 0, j = 0;
  const results = [];
  while (i < text.length) {
    if (text[i] === pattern[j]) { i++; j++; }
    if (j === pattern.length) {
      results.push(i - j);
      j = lps[j - 1];
    } else if (i < text.length && text[i] !== pattern[j]) {
      j > 0 ? (j = lps[j - 1]) : i++;
    }
  }
  return results;
}

class Node {
  constructor(data) {
    this.data = data;
    this.next = null;
  }
}

class LinkedList {
  constructor() {
    this.head = null;
  }

  // Insert at head — O(1)
  prepend(data) {
    const node = new Node(data);
    node.next = this.head;
    this.head = node;
  }

  // Insert at tail — O(n)
  append(data) {
    const node = new Node(data);
    if (!this.head) { this.head = node; return; }
    let cur = this.head;
    while (cur.next) cur = cur.next;
    cur.next = node;
  }

  // Delete node by value — O(n)
  delete(data) {
    if (!this.head) return;
    if (this.head.data === data) { this.head = this.head.next; return; }
    let cur = this.head;
    while (cur.next && cur.next.data !== data) cur = cur.next;
    if (cur.next) cur.next = cur.next.next;
  }

  // Print all — O(n)
  print() {
    let cur = this.head;
    const vals = [];
    while (cur) { vals.push(cur.data); cur = cur.next; }
    console.log(vals.join(' -> '));
  }
}

function hasCycle(head) {
  let slow = head, fast = head;
  while (fast && fast.next) {
    slow = slow.next;
    fast = fast.next.next;
    if (slow === fast) return true;
  }
  return false;
}

function reverseList(head) {
  let prev = null, cur = head;
  while (cur) {
    const next = cur.next;
    cur.next = prev;
    prev = cur;
    cur = next;
  }
  return prev;
}

class DoublyNode {
  constructor(data) {
    this.data = data;
    this.prev = null;
    this.next = null;
  }
}

class DoublyLinkedList {
  constructor() {
    this.head = null;
    this.tail = null;
  }

  append(data) {
    const node = new DoublyNode(data);
    if (!this.tail) {
      this.head = this.tail = node;
    } else {
      node.prev = this.tail;
      this.tail.next = node;
      this.tail = node;
    }
  }

  deleteTail() {
    if (!this.tail) return;
    if (this.head === this.tail) { this.head = this.tail = null; return; }
    this.tail = this.tail.prev;
    this.tail.next = null;
  }
}

