class MinHeap {
  constructor() { this.heap = []; }

  insert(val) {
    this.heap.push(val);
    this._bubbleUp(this.heap.length - 1);
  }

  extractMin() {
    const min = this.heap[0];
    const last = this.heap.pop();
    if (this.heap.length) {
      this.heap[0] = last;
      this._sinkDown(0);
    }
    return min;
  }

  _bubbleUp(i) {
    while (i > 0) {
      const parent = Math.floor((i - 1) / 2);
      if (this.heap[parent] > this.heap[i]) {
        [this.heap[parent], this.heap[i]] = [this.heap[i], this.heap[parent]];
        i = parent;
      } else break;
    }
  }

  _sinkDown(i) {
    const n = this.heap.length;
    while (true) {
      let min = i, l = 2*i+1, r = 2*i+2;
      if (l < n && this.heap[l] < this.heap[min]) min = l;
      if (r < n && this.heap[r] < this.heap[min]) min = r;
      if (min === i) break;
      [this.heap[min], this.heap[i]] = [this.heap[i], this.heap[min]];
      i = min;
    }
  }
}

function hash(key, size) {
  let h = 0;
  for (let c of key) h = (h + c.charCodeAt(0)) % size;
  return h;
}

class HashMap {
  constructor(size = 53) {
    this.table = new Array(size);
    this.size = size;
  }
  _hash(key) {
    let h = 0;
    for (let c of String(key)) h = (h * 31 + c.charCodeAt(0)) % this.size;
    return h;
  }
  set(key, value) {
    const i = this._hash(key);
    if (!this.table[i]) this.table[i] = [];
    const existing = this.table[i].find(e => e[0] === key);
    if (existing) existing[1] = value;
    else this.table[i].push([key, value]);
  }
  get(key) {
    const i = this._hash(key);
    if (!this.table[i]) return undefined;
    return this.table[i].find(e => e[0] === key)?.[1];
  }
}

// Two Sum — O(n)
function twoSum(nums, target) {
  const map = {};
  for (let i = 0; i < nums.length; i++) {
    const complement = target - nums[i];
    if (map[complement] !== undefined) return [map[complement], i];
    map[nums[i]] = i;
  }
}

// First non-repeating character — O(n)
function firstUnique(s) {
