  for (let c of s) freq[c] = (freq[c] || 0) + 1;
  for (let c of s) if (freq[c] === 1) return c;
  return null;
}

// Adjacency List Graph
class Graph {
  constructor() { this.adj = {}; }

  addVertex(v) {
    if (!this.adj[v]) this.adj[v] = [];
  }

  addEdge(u, v) { // undirected
    this.adj[u].push(v);
    this.adj[v].push(u);
  }

  addDirectedEdge(u, v) {
    this.adj[u].push(v);
  }
}

function bfs(graph, start) {
  const visited = new Set([start]);
  const queue = [start];
  const order = [];
  while (queue.length) {
    const node = queue.shift();
    order.push(node);
    for (let neighbor of graph.adj[node] || []) {
      if (!visited.has(neighbor)) {
        visited.add(neighbor);
        queue.push(neighbor);
      }
    }
  }
  return order;
}

// Recursive DFS
