}

// Iterative DFS
function dfsIterative(graph, start) {
  const visited = new Set();
  const stack = [start];
  while (stack.length) {
    const node = stack.pop();
    if (!visited.has(node)) {
      visited.add(node);
      console.log(node);
      for (let n of graph.adj[node] || []) stack.push(n);
    }
  }
}

function dijkstra(graph, start) {
  const dist = {};
  for (let v in graph) dist[v] = Infinity;
  dist[start] = 0;

  // Simple implementation with array as priority queue
  const visited = new Set();
  const nodes = Object.keys(graph);

  while (true) {
    // Get unvisited node with min dist
    let u = null;
    for (let v of nodes) {
      if (!visited.has(v) && (u === null || dist[v] < dist[u])) u = v;
    }
    if (u === null || dist[u] === Infinity) break;
    visited.add(u);
    for (let [neighbor, weight] of graph[u]) {
      const newDist = dist[u] + weight;
      if (newDist < dist[neighbor]) dist[neighbor] = newDist;
    }
  }
  return dist;
}

